prompt --application/shared_components/navigation/lists/quadrianomali
begin
wwv_flow_imp_shared.create_list(
 p_id=>wwv_flow_imp.id(14029650737886206)
,p_name=>'QuadriAnomali'
,p_list_type=>'SQL_QUERY'
,p_list_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select lvl, label, ',
'       apex_util.prepare_url(p_url => ''f?p=''||v(''APP_ID'')||'':4:''||v(''SESSION'')||''::NO::P4_AREAGEO,P4_ANOMALIA:''||v(''P1_AREAGEO'')||'',''||label) as target,',
'    attribute1, attribute2, attribute3, attribute4,',
'    attribute5, attribute6, attribute7',
'from (',
'select null as lvl,''Contatori'' label, ''#'' as target,',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       count(*) attribute5, null attribute6, null attribute7, ''A'' orderby ',
'from aes_tlr.tbl_stat_installazione si',
'     INNER JOIN utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.TBL_aree a on al.id_area = a.id',
'where gprs= ''Si''',
'and nvl(:P1_AREAGEO, a.id) = a.id',
'and sysdate-nvl(lastclock_kam,sysdate)>2 ',
'and sysdate-nvl(lastclock_hyd,sysdate)>2 ',
'and sysdate-nvl(lastclock_uh50,sysdate)>2',
'union',
'select null as lvl,''Regolatori'' label, ''#'' as target,',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       count(*) attribute5, null attribute6, null attribute7, ''B'' orderby ',
'from aes_tlr.tbl_stat_installazione si',
'     INNER JOIN utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.tbl_aree a on al.id_area = a.id',
'where gprs= ''Si''',
'and nvl(:P1_AREAGEO, a.id) = a.id',
'and sysdate-nvl(lastclock_dan,sysdate)>2 ',
'and sysdate-nvl(lastclock_sie,sysdate)>2 ',
'and sysdate-nvl(lastclock_rvl,sysdate)>2',
') order by orderby',
'',
''))
,p_list_status=>'PUBLIC'
,p_version_scn=>1
);
end;
/
