'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       239 attribute5, null attribute6, null attribute7, ''B'' orderby from dual',
'union ',
'select null as lvl,''In valutazione'' label, ''javascript:void(0);'' as target,',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       14 attribute5, null attribute6, null attribute7, ''C'' orderby from dual',
') order by orderby',
''))
