prompt --application/shared_components/navigation/lists/quadriattivati
begin
wwv_flow_imp_shared.create_list(
 p_id=>wwv_flow_imp.id(14112610393347462)
,p_name=>'QuadriAttivati'
,p_list_type=>'SQL_QUERY'
,p_list_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select null as lvl, label, ',
'       apex_util.prepare_url(p_url => ''f?p=''||v(''APP_ID'')||'':2:''||v(''SESSION'')||''::NO::P2_AREAGEO,P2_ANNO:''||v(''P1_AREAGEO'')||'',''||label) as target,',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       value attribute5, null attribute6, null attribute7',
'from (',
'select count(*) value, substr(in_funz_dal,7) label',
'from aes_tlr.v_aes_imprese_totali ai',
'     inner join utenti_tlg.tbl_area_localita al on ai.localita_breve = al.localita_breve',
'     inner join utenti_tlg.tbl_aree a on a.id = al.id_area',
'where substr(in_funz_dal,7)>= to_char(to_number(to_char(sysdate,''yyyy''))-1)',
'and   nvl(:P1_AREAGEO, a.id) = a.id',
'group by substr(in_funz_dal,7)',
')',
''))
,p_list_status=>'PUBLIC'
,p_version_scn=>1
);
end;
/
prompt --application/shared_components/navigation/lists/quadrionoff
begin
wwv_flow_imp_shared.create_list(
 p_id=>wwv_flow_imp.id(14128047185074911)
,p_name=>'QuadriOnOff'
,p_list_type=>'SQL_QUERY'
,p_list_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select lvl, label, ',
'target, ',
'    attribute1, attribute2, attribute3, attribute4,',
'    attribute5, attribute6, attribute7',
'from (',
'select null as lvl,''On line'' label, ''#'' as target, ',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       count(*) attribute5, null attribute6, null attribute7, ''A'' orderby ',
'from aes_tlr.tbl_stat_installazione si',
'     inner join utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.TBL_AREE a on a.id = al.id_area',
'where trunc(DATA_ULTIMO_INVIO) = trunc(sysdate)',
'and   nvl(:P1_AREAGEO, a.id) = a.id',
'union',
'select null as lvl,''off line da '' || to_char(trunc(sysdate)- trunc(DATA_ULTIMO_INVIO)) label,',
'       apex_util.prepare_url(p_url => ''f?p=''||v(''APP_ID'')||'':5:''||v(''SESSION'')||''::NO::P5_AREAGEO,P5_GIORNI:''||v(''P1_AREAGEO'')||'',''||to_char(trunc(sysdate)- trunc(DATA_ULTIMO_INVIO))) as target, ',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       count(*) attribute5, null attribute6, null attribute7, ''B'' orderby ',
'from aes_tlr.tbl_stat_installazione si',
'     inner join utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.TBL_AREE a on a.id = al.id_area',
'where   nvl(:P1_AREAGEO, a.id) = a.id',
'group by trunc(sysdate)- trunc(DATA_ULTIMO_INVIO)--, to_char(rownum)',
'having trunc(sysdate)- trunc(DATA_ULTIMO_INVIO) between 1 and 6',
'--order by 2 desc',
'union',
'select null as lvl,''off line da 6+ gg'' label,',
'       apex_util.prepare_url(p_url => ''f?p=''||v(''APP_ID'')||'':5:''||v(''SESSION'')||''::NO::P5_AREAGEO,P5_GIORNI:''||v(''P1_AREAGEO'')||'',''||''> 6'') as target, ',
'       null attribute1, null attribute2, null attribute3, null attribute4, ',
'       count(*) attribute5, null attribute6, null attribute7, ''C'' orderby ',
'from aes_tlr.tbl_stat_installazione si',
'     inner join utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.TBL_AREE a on a.id = al.id_area',
'where trunc(sysdate)- trunc(DATA_ULTIMO_INVIO) > 6',
'and   nvl(:P1_AREAGEO, a.id) = a.id',
') order by label desc;'))
,p_list_status=>'PUBLIC'
,p_version_scn=>1
);
end;
/
