prompt --application/shared_components/logic/application_processes/download_estrazione
begin
wwv_flow_imp_shared.create_flow_process(
 p_id=>wwv_flow_imp.id(198277110571316122)
,p_process_sequence=>1
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'download_estrazione'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'    DECLARE',
'        l_id_estrazione VARCHAR2(100);',
'    BEGIN',
'        l_id_estrazione := v(''P''|| :APP_PAGE_ID ||''_ID_ESTRAZIONE'');',
'        p_download_estrazione(''ESTRAZIONI'', ''estrazione_'' || l_id_estrazione || ''.zip'');',
'    EXCEPTION',
'        WHEN OTHERS THEN',
'            exporttlr.p_log_messaggio(''application_process'', 1000, ''Errore durante esecuzione di p_download_estrazione: '' || SQLERRM, '''');',
'    END;'))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>'Errore nel processo'
,p_security_scheme=>'MUST_NOT_BE_PUBLIC_USER'
,p_version_scn=>1
);
end;
