'     --inner join monitoraggio_tlg.hosts_profiles_ext hp on h.hostid = hp.hostid',
'     inner join aes_tlr.v_zbx_imprese hp on substr(h.host,1,16) = hp.sede',
'--     inner join monitoraggio_tlg.items i on i.hostid = h.hostid and key_ = ''SIE255_02_04''',
'where nvl(hp.latitude, 0) != 0',
'and nvl(:P1_AREAGEO, h.areaid) = h.areaid',
'--and rownum < 2',
'',
'/*',
'select host, latitude, longitude ',
'from monitoraggio_tlg.v_zbx_hosts h ',
'     inner join monitoraggio_tlg.hosts_profiles_ext hp on h.hostid = hp.hostid',
'where hp.latitude is not null',
'and nvl(:P1_AREAGEO, h.areaid) = h.areaid',
