,p_computation_type=>'FUNCTION_BODY'
,p_computation_language=>'PLSQL'
,p_computation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  lastclock integer;',
'  giorno date;',
'  oggi varchar2(200);',
'begin',
'  SELECT max("range_start_integer") into lastclock FROM "timescaledb_information"."chunks"@pglink where "hypertable_name" = ''history'';',
'  select max(clock) into lastclock from monitoraggio_tlg.v_zbx_history where clock > lastclock;',
'  select aes_tlr.pkg_functions.f_timestamp_tz(lastclock) into giorno from dual;',
'  select ''Ultimo dato dal campo: '' || to_char(giorno, ''dd-mon-yyyy'') || '' alle ore '' || to_char(giorno, ''HH24:MI:SS'') into oggi from dual;',
'',
'  --htp.p(''&nbsp;'');',
'  --htp.center(''<p>'' || oggi);',
'  --htp.p(''&nbsp;'');',
'  return oggi;',
'end;',
''))
,p_compute_when_type=>'NEVER'
);
