 p_id=>wwv_flow_imp.id(23416035355754170)
,p_plug_name=>'TipologiaQuadri'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(11940482784520749)
,p_plug_display_sequence=>40
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select a.descrizione area, si.* from aes_tlr.v_stat_installazione_all si',
'     inner join utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.TBL_AREE a on a.id = al.id_area',
'where to_char(data_inst_quadro,''yyyy'') = ',
'  case :P3_ANNO',
'    when ''precedente'' then to_char(add_months(sysdate,-12),''yyyy'')',
'  else to_char(sysdate,''yyyy'')',
'  end',
'and   nvl(:P3_AREAGEO, a.id) = a.id',
'and   nvl(:P3_TIPOQUADRO, si.tipo_quadro) = si.tipo_quadro',
'--where to_char(data_inizio_telegest,''yyyy'') = :P3_ANNO',
''))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>'TipologiaQuadri'
);
