 p_id=>wwv_flow_imp.id(23442553226973136)
,p_plug_name=>'AnomalieContatori'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(11940482784520749)
,p_plug_display_sequence=>30
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select a.descrizione area, si.*',
'from aes_tlr.tbl_stat_installazione si',
'     INNER JOIN utenti_tlg.TBL_AREA_LOCALITA al ON substr(si.nome_sst, 4,2) = al.LOCALITA_BREVE',
'     inner join utenti_tlg.tbl_aree a on al.id_area = a.id',
'where gprs= ''Si''',
'and nvl(:P4_AREAGEO, a.id) = a.id',
'and sysdate-nvl(lastclock_kam,sysdate)>2 ',
'and sysdate-nvl(lastclock_hyd,sysdate)>2 ',
'and sysdate-nvl(lastclock_uh50,sysdate)>2'))
,p_plug_source_type=>'NATIVE_IR'
