,p_plug_name=>'Report 1'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(11940482784520749)
,p_plug_display_sequence=>20
,p_plug_grid_column_span=>11
,p_plug_display_column=>1
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT tau.ID_UTENTE, tau.NOME_UTENTE, tau.ID_PROFILO, tau.ID_IMPRESA, tau.E_MAIL, tau.DATA_FINE_VALIDITA, tau.LAST_LOGIN, tau.LDAP_ACCOUNT, ',
'       tau.RUOLO_MONITORAGGIO, tau.LAST_IP, tau.ID_RUOLO_PORTALE,',
'       listagg (a.descrizione, ''<BR>'') WITHIN GROUP (ORDER BY null) aree',
'FROM TBL_ANAG_UTENTI tau ',
'CROSS JOIN table(CAST(MULTISET( SELECT LEVEL FROM dual',
'                                CONNECT BY LEVEL <= regexp_count(tau.ID_AREE, '':'') + 1)',
'                                AS sys.odcinumberlist )) x',
'LEFT JOIN tbl_aree  a ON a.id = regexp_substr(tau.ID_AREE, ''[^:]+'', 1, x.column_value)',
'group BY tau.ID_UTENTE, tau.NOME_UTENTE, tau.ID_PROFILO, tau.ID_IMPRESA, tau.E_MAIL, tau.DATA_FINE_VALIDITA, tau.LAST_LOGIN, tau.LDAP_ACCOUNT, ',
'       tau.RUOLO_MONITORAGGIO, tau.LAST_IP, tau.ID_RUOLO_PORTALE'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>'Report 1'
