,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var itemValue = $v(''P7_ID_AREE_UTENTE_COPIATO'');',
'var ids = itemValue.split('':'');',
'var areas = [];',
'',
'for (var i = 0; i < ids.length; i++) {',
'    if (ids[i] === ''1'') {',
'        areas.push(''TORINO'');',
'    } else if (ids[i] === ''2'') {',
'        areas.push(''GENOVA'');',
'    } else if (ids[i] === ''3'') {',
'        areas.push(''EMILIA'');',
'    } else if (ids[i] === ''4'') {',
'        areas.push(''DOGLIANI'');',
'    }',
'}',
'',
'$s(''P7_ID_AREE'', ids, areas);',
''))
);
