wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(54806258401828320)
,p_plug_name=>'Elenco Gruppi Utenti'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>wwv_flow_imp.id(11944735294520751)
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT usrgrpid, name, count(nome_utente) tot_utenti, ',
'replace(rtrim(ltrim(replace(JSON_ARRAYAGG(nome_utente order by nome_utente returning clob),''"'',''''),''[''), '']''),'','','', '') "Elenco Utenti"',
'FROM (',
'SELECT u.usrgrpid usrgrpid, u.name name,',
'upper(tau.nome_utente) ',
'--''<a class=uoh href=portaleunico/r/monitoraggio-tlg/scheda-utente?P36_ID_UTENTE=''||tau.ID_UTENTE||''&session=''||APEX_CUSTOM_AUTH.GET_SESSION_ID||''>''||upper(tau.nome_utente) ||''</a>''',
'nome_utente, ',
'tau.ID_UTENTE',
'FROM monitoraggio_tlg.USRGRP u ',
'     LEFT OUTER JOIN monitoraggio_tlg.USERS_GROUPS_NEW  ug ON u.usrgrpid = ug.USRGRPID ',
'     LEFT OUTER JOIN utenti_tlg.TBL_ANAG_UTENTI tau ON ug.USERID = tau.ID_UTENTE',
')',
'GROUP BY usrgrpid, name',
';'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
