,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// Clear previous selections, if any',
'$s("P21_SELECTED_ROWS", "");',
'// IG static id is defined as emp',
'var gridView = apex.region("IG_USRID").widget().interactiveGrid("getViews").grid;',
'var records = gridView.getSelectedRecords();',
'var empNo;',
'',
'// define empty JSON object to hold selected rows',
'var selRecords = {',
'	"rows": []',
'};',
'',
'var selRecordsJSON;',
'',
'if (records.length > 0) {',
'	if (confirm("Vuoi associare i Baricentri al gruppo?")) {',
'		$.each(records, function(i, r) {',
'			// employee number defined as PK for IG',
'			empNo = gridView.model.getRecordId(r);',
'			// you can also get other columns values using below code',
'			// ENAME is column name in IG query',
'			//empName = gridView.model.getValue(r, "ENAME");',
'			// Push selected rows into an array',
'			selRecords.rows.push({',
'				"grpID": empNo',
'			});',
'		});',
'		// convert JSON into string',
'		selRecordsJSON = JSON.stringify(selRecords);',
'		console.log(selRecordsJSON);',
'		apex.page.submit({',
'			request: "SAVE",',
'			set: {',
'				"P21_SELECTED_ROWS": selRecordsJSON',
'			},',
'			showWait: true',
'		});',
'	}',
'} else {',
'	alert("Please select atleast one Baricentro.");',
'}'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(28126072236817157)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'AddGroupToRights'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_groupid   monitoraggio_tlg.groups.groupid%type;',
'    l_values    apex_json.t_values;',
'    l_row_count PLS_INTEGER;',
'    l_rid       PLS_INTEGER;',
'BEGIN',
'    apex_debug.message(''inside process Bulk Add User To Group'');',
'    -- parse text to JSON',
'    apex_json.parse(p_values => l_values, p_source => :P21_SELECTED_ROWS);',
'    apex_debug.message(''In process: ''|| :P21_SELECTED_ROWS);',
'    -- get number of rows selected',
'    l_row_count := apex_json.get_count(p_path => ''rows'', p_values => l_values);',
'    apex_debug.message(''In process - count: ''|| l_row_count);',
'    -- loop through the selected rows',
'    FOR i IN 1..l_row_count LOOP',
'        -- get Primary Key value from JSON data',
'        l_groupid := null;',
