'        apex_debug.message(''l_groupid'' || l_groupid);',
'        -- update employee commission',
'        select max(rightid)+1 into l_rid from monitoraggio_tlg.rights;',
'        INSERT INTO monitoraggio_tlg.rights (rightid, groupid, permission, id) values (l_rid,:P21_USRGRPID, 3, l_groupid);',
'    END LOOP;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(28123029355817154)
