wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(327470165041209162)
,p_name=>'new'
,p_region_name=>'reportjob'
,p_template=>wwv_flow_imp.id(11944735294520751)
,p_display_sequence=>30
,p_include_in_reg_disp_sel_yn=>'Y'
,p_region_template_options=>'#DEFAULT#:t-Region--noPadding:t-Region--removeHeader js-removeLandmark:t-Region--noBorder:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'    SELECT req_start_date, actual_start_date, run_duration, status, log_date ',
'    FROM all_scheduler_job_run_details',
'    WHERE owner = :P34_OWNER',
'    AND job_name = :P34_JOB',
'UNION ALL',
'    SELECT req_start_date, actual_start_date, run_duration, status, log_date ',
'    FROM all_scheduler_job_run_details@mobitlg.localdomain',
'    WHERE owner = :P34_OWNER',
'    AND job_name = :P34_JOB',
'UNION ALL',
'    SELECT req_start_date, actual_start_date, run_duration, status, log_date ',
'    FROM all_scheduler_job_run_details@alert.localdomain',
'    WHERE owner = :P34_OWNER',
'    AND job_name = :P34_JOB',
'UNION ALL',
'    SELECT CAST(NULL AS DATE) AS req_start_date,',
'    CAST(NULL AS DATE) AS actual_start_date,',
'    r.elapsed_time AS run_duration,',
'    ''RUNNING'' AS status,',
'    CAST(NULL AS DATE) AS log_date',
'    FROM all_scheduler_running_jobs r',
'    WHERE r.owner = :P34_OWNER',
'    AND r.job_name = :P34_JOB',
'UNION ALL',
'    SELECT CAST(NULL AS DATE) AS req_start_date,',
'    CAST(NULL AS DATE) AS actual_start_date,',
'    GET_JOB_ELAPSED_TIME@mobitlg.localdomain(:P34_OWNER, :P34_JOB) AS run_duration,',
'    ''RUNNING'' AS status,',
'    CAST(NULL AS DATE) AS log_date',
'    FROM dual',
'    WHERE :P34_OWNER = :P34_OWNER ',
'    AND :P34_JOB = :P34_JOB',
'    AND GET_JOB_RUNNING_COUNT@mobitlg.localdomain(:P34_OWNER, :P34_JOB) > 0',
'UNION ALL',
'    SELECT CAST(NULL AS DATE) AS req_start_date,',
'    CAST(NULL AS DATE) AS actual_start_date,',
'    GET_JOB_ELAPSED_TIME@alert.localdomain(:P34_OWNER, :P34_JOB) AS run_duration,',
'    ''RUNNING'' AS status,',
'    CAST(NULL AS DATE) AS log_date',
'    FROM dual',
'    WHERE :P34_OWNER = :P34_OWNER ',
'    AND :P34_JOB = :P34_JOB',
'    AND GET_JOB_RUNNING_COUNT@alert.localdomain(:P34_OWNER, :P34_JOB) > 0',
'    ORDER BY req_start_date DESC'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>wwv_flow_imp.id(11979778891520773)
,p_query_num_rows=>50
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
